using System.Text.Json.Serialization;  namespace BulkRequest.Config {     internal class ServersGroupInfo : IJsonOnDeserialized     {         public required string Name { get; init; }         public required string Provider { get; init; }         public required Dictionary<string, ServerDatabasesInfo> Servers { get; init; }         public Dictionary<string, DatabaseInfo> Databases { get; init; } = [];          public void OnDeserialized()         {             Databases.Clear();              foreach (ServerDatabasesInfo server in Servers.Values)             {                 foreach (DatabaseInfo db in server.Databases.Values)                 {                     Databases.Add(db.Name, db);                 }             }         }     } }